import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/launcher-screen.B4Y3DSWp.js";const o=JSON.parse(`{"title":"Installing Fabric on Windows","description":"A step-by-step guide on how to install Fabric on Windows.","frontmatter":{"title":"Installing Fabric on Windows","description":"A step-by-step guide on how to install Fabric on Windows.","authors":["Benonardo","ezfe","IMB11","modmuss50"],"next":false,"files":[]},"headers":[],"relativePath":"players/installing-fabric/windows.md","filePath":"players/installing-fabric/windows.md","lastUpdated":1768516421000}`);var s={name:`players/installing-fabric/windows.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Installing Fabric on Windows <a class="header-anchor" href="#h1" aria-label="Permalink to “Installing Fabric on Windows”">​</a></h1><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Download the Fabric Installer <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Download the Fabric Installer”">​</a></h2><p>Download the <code>.exe</code> version of the Fabric Installer from the <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Fabric Website</a>, by clicking on <code>Download for Windows</code>.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>The <code>.exe</code> version for Windows does not require Java to be installed, because it uses the Java bundled with the official Minecraft Launcher.</p></div><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Run the Fabric Installer <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Run the Fabric Installer”">​</a></h2><p>Close Minecraft and the Minecraft Launcher first before running the installer.</p><p>Once you open the installer, you should see a screen like this:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Fabric Installer with &quot;Install&quot; highlighted" loading="lazy"></p><p>Select your desired Minecraft version and click <code>Install</code>. Make sure that <code>Create Profile</code> is checked.</p><h2 id="3-finish-setup" tabindex="-1">3. Finish Setup <a class="header-anchor" href="#3-finish-setup" aria-label="Permalink to “3. Finish Setup”">​</a></h2><p>Once installation completes, open the Minecraft Launcher. Then select the Fabric profile from the version dropdown and click Play.</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Minecraft Launcher with Fabric profile selected" loading="lazy"></p><p>You can now add mods to your game. See the <a href="./../finding-mods">Finding Trustworthy Mods</a> guide for info.</p><p>If you encounter issues, feel free to ask for help in the <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> in the <code>#player-support</code> channel.</p>`,14)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};